// ========================================
// GL365 HubSpot Event Normalizer
// ========================================
// Maps HubSpot webhook payloads to GL365 journal format.
//
// HubSpot subscription types:
//   contact.creation       → new_customer
//   contact.propertyChange → contact_updated
//   deal.creation          → deal_created
//   deal.propertyChange    → deal_updated
//   meeting.creation       → booking_created
//   engagement.creation    → engagement_logged

const input = $input.first().json;

// HubSpot sends arrays of events
const events = Array.isArray(input) ? input : [input];
const event = events[0] || {};

const subscriptionType = event.subscriptionType || event.type || '';
const objectId = event.objectId || '';
const propertyName = event.propertyName || '';
const propertyValue = event.propertyValue || '';

const eventMap = {
  'contact.creation': 'new_customer',
  'contact.propertyChange': 'contact_updated',
  'deal.creation': 'deal_created',
  'deal.propertyChange': 'deal_updated',
  'meeting.creation': 'booking_created',
  'engagement.creation': 'engagement_logged'
};

let importance = 'normal';
if (subscriptionType === 'deal.creation') importance = 'high';
if (propertyName === 'dealstage' && propertyValue === 'closedwon') importance = 'critical';
if (propertyName === 'dealstage' && propertyValue === 'closedlost') importance = 'high';

let sentiment = 'neutral';
if (propertyName === 'dealstage' && propertyValue === 'closedwon') sentiment = 'positive';
if (propertyName === 'dealstage' && propertyValue === 'closedlost') sentiment = 'negative';
if (subscriptionType === 'meeting.creation') sentiment = 'positive';

// HubSpot doesn't include full contact data in webhooks —
// in production, you'd fetch from HubSpot API: GET /crm/v3/objects/contacts/{objectId}
const contact = event.properties || {};

const normalized = {
  tenant_id: event.metadata?.tenant_id || '',
  contact_phone: contact.phone || '',
  contact_email: contact.email || '',
  contact_name: [contact.firstname, contact.lastname].filter(Boolean).join(' ') || '',
  source: 'hubspot',
  event_type: eventMap[subscriptionType] || subscriptionType || 'unknown',
  raw_summary: `HubSpot ${subscriptionType}: objectId=${objectId}${propertyName ? `, ${propertyName}=${propertyValue}` : ''}`,
  raw_data: input,
  sentiment,
  importance,
  hubspot_object_id: objectId,
  hubspot_property: propertyName,
  hubspot_value: propertyValue
};

return [{ json: normalized }];

const input = $input.first().json;
const prevData = $('Normalize HubSpot Event').first().json;
let summary = '';
try { summary = input.choices?.[0]?.message?.content || prevData.raw_summary; } catch { summary = prevData.raw_summary; }
return [{ json: { ...prevData, summary: summary.trim().replace(/^["']|["']$/g, '') } }];
